+            Constraint::Percentage(split_state.two_pane_detail_pct(bp)),
+        ])
+        .split(body);
+    vec![SplitterHitBox {
+        target: SplitterTarget::TwoPane { breakpoint: bp },
+        rect: splitter_rect_between(panes[0], panes[1]),
